@page "/settings"
@using sv_4dca3b5dfd64438caa61a8dac44a1c38.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastMessage is not null)
        {
            <div class="toast-notification @(_toastFading ? "fade-out" : "")">
                <span class="toast-icon">✓</span> @_toastMessage
            </div>
        }
    </div>
</div>

@* ── Confirmation Modal ── *@
@if (_showConfirmDialog)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Confirm Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> in <strong>@_sessionToRevoke?.Location</strong>?</p>
                    <p class="text-muted mb-0">This will sign that device out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    // ── Section navigation ──
    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastFading;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _profileName = "";
    private string _profileEmail = "";
    private string _profileBio = "";
    private string _profileAvatarUrl = "";
    private bool _savingProfile;

    // ── Notification state ──
    private bool _emailNotif;
    private bool _pushNotif;
    private bool _weeklyDigest;
    private List<ChannelEntry> _channels = [];
    private bool _savingNotifs;

    private class ChannelEntry
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }

    // ── Security state ──
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;
    private bool _showConfirmDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // ── Appearance state ──
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _savingAppearance;

    private static readonly string[] _availableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadAllDataAsync();
        _loading = false;
    }

    private async Task LoadAllDataAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        ApplyProfile(await profileTask);
        ApplyNotifications(await notifsTask);
        _security = await securityTask;
        ApplyAppearance(await appearanceTask);
    }

    // ── Profile ──

    private void ApplyProfile(UserProfile p)
    {
        _savedProfile = p;
        _profileName = p.DisplayName;
        _profileEmail = p.Email;
        _profileBio = p.Bio;
        _profileAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        _savingProfile = true;
        var profile = new UserProfile(_profileName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _savingProfile = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    // ── Notifications ──

    private void ApplyNotifications(NotificationPrefs n)
    {
        _emailNotif = n.EmailNotifications;
        _pushNotif = n.PushNotifications;
        _weeklyDigest = n.WeeklyDigest;
        _channels = n.MutedChannels
            .Select(c => new ChannelEntry { Name = c, Muted = true })
            .ToList();
    }

    private async Task SaveNotifications()
    {
        _savingNotifs = true;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotif, _pushNotif, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _savingNotifs = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }
        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _changingPassword = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Password updated successfully.");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showConfirmDialog = true;
    }

    private void CancelRevoke()
    {
        _showConfirmDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _revoking = false;
        _showConfirmDialog = false;
        _sessionToRevoke = null;
        _security = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Session revoked.");
    }

    // ── Appearance ──

    private void ApplyAppearance(AppearanceSettings a)
    {
        _theme = a.Theme;
        _fontSize = a.FontSize;
        _language = a.Language;
        _compactMode = a.CompactMode;
    }

    private async Task SaveAppearance()
    {
        _savingAppearance = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _savingAppearance = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast helper ──

    private void ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        _toastFading = false;
        _ = DismissToastAsync(_toastCts.Token);
    }

    private async Task DismissToastAsync(CancellationToken ct)
    {
        try
        {
            await Task.Delay(2500, ct);
            _toastFading = true;
            StateHasChanged();
            await Task.Delay(500, ct);
            _toastMessage = null;
            _toastFading = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Render fragments ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section>
            <h3 class="section-heading">Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label" for="displayName">Display Name</label>
                        <input id="displayName" class="form-control" @bind="_profileName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="email">Email</label>
                        <input id="email" type="email" class="form-control" @bind="_profileEmail" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="bio">Bio</label>
                        <textarea id="bio" class="form-control" rows="4" @bind="_profileBio"></textarea>
                    </div>
                </div>

                <div class="col-md-4">
                    <div class="avatar-preview-card text-center">
                        <div class="avatar-circle mb-2">
                            @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                            {
                                <img src="@_profileAvatarUrl" alt="Avatar" />
                            }
                            else
                            {
                                <span class="avatar-placeholder">👤</span>
                            }
                        </div>
                        <label class="form-label" for="avatarUrl">Avatar URL</label>
                        <input id="avatarUrl" class="form-control form-control-sm" @bind="_profileAvatarUrl" placeholder="https://..." />
                    </div>
                </div>
            </div>

            <div class="mt-4 d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_savingProfile">
                    @if (_savingProfile) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section>
            <h3 class="section-heading">Notifications</h3>
            <p class="text-muted">Choose how and when you want to be notified.</p>
            <hr />

            <div class="mb-4">
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotif" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotif" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            @if (_channels.Count > 0)
            {
                <h5>Muted Channels</h5>
                <div class="channel-list mb-4">
                    @foreach (var channel in _channels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                                   @bind="channel.Muted" />
                            <label class="form-check-label" for="@($"ch-{channel.Name}")">@channel.Name</label>
                        </div>
                    }
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_savingNotifs">
                @if (_savingNotifs) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section>
            <h3 class="section-heading">Security</h3>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
            <hr />

            @* Change Password Panel *@
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        @if (_passwordError is not null)
                        {
                            <div class="alert alert-danger py-2">@_passwordError</div>
                        }
                        <div class="mb-3">
                            <label class="form-label" for="currentPwd">Current Password</label>
                            <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label" for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label" for="confirmPwd">Confirm Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_changingPassword">
                            @if (_changingPassword) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <small class="text-muted ms-3">Last changed: @_security.LastPasswordChange.Value.ToString("MMM d, yyyy")</small>
                        }
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_security?.TwoFactorEnabled == true ? "bg-success" : "bg-secondary")">
                            @(_security?.TwoFactorEnabled == true ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" checked="@(_security?.TwoFactorEnabled ?? false)" disabled />
                    </div>
                </div>
            </div>

            @* Active Sessions *@
            <h5>Active Sessions</h5>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @{ var isFirst = true; }
                            @foreach (var session in _security.Sessions)
                            {
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isFirst)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                    <td>
                                        @if (!isFirst)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                                isFirst = false;
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions found.</p>
            }
        </section>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section>
            <h3 class="section-heading">Appearance</h3>
            <p class="text-muted">Customize how the application looks and feels.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-7">
                    @* Theme *@
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Theme</label>
                        <div class="d-flex gap-3">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme"
                                           id="@($"theme-{theme}")" value="@theme"
                                           checked="@(_theme == theme)"
                                           @onchange="() => _theme = theme" />
                                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                                </div>
                            }
                        </div>
                    </div>

                    @* Font size *@
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Font Size</label>
                        <div class="d-flex gap-3">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize"
                                           id="@($"fs-{size}")" value="@size"
                                           checked="@(_fontSize == size)"
                                           @onchange="() => _fontSize = size" />
                                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                                </div>
                            }
                        </div>
                    </div>

                    @* Language *@
                    <div class="mb-4">
                        <label class="form-label fw-semibold" for="language">Language</label>
                        <select id="language" class="form-select" style="max-width: 250px;"
                                @bind="_language">
                            @foreach (var lang in _availableLanguages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    @* Compact mode *@
                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_savingAppearance">
                        @if (_savingAppearance) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

